import React from 'react'
import useBook from '../hooks/useBook';
import { Outlet, useNavigate } from 'react-router-dom';
import { Button, TextField, Grid, Paper } from '@mui/material';
import { Search, FilterList } from '@mui/icons-material';

const SearchBar = () => {

    const { search, dataSearch, getBookList, loading } = useBook()

    const { query } = search

    const navigate = useNavigate();

    const handleSubmit = e => {
        e.preventDefault()
        getBookList(query, loading)
        navigate("list", { replace: true });
    }

  return (
      <>
      
        <div className='search-bar mt-4'>
        <form onSubmit={handleSubmit}>
       
            <Grid container justifyContent="center" alignItems="center" spacing={2}>
            <Grid item xs={8}>
                <TextField
                fullWidth
                placeholder='Buscar por título, autor...'
                type="text"
                name="query"
                onChange={dataSearch}
                value={query}
                variant="outlined"
                size="small"
                />
            </Grid>
            <Grid item xs='auto'>
                <Button type="button" variant="contained" color="primary" onClick={() => {}} id="btn-filter">
                <FilterList />
                </Button>
            </Grid>
            <Grid item xs='auto'>
                <Button type="submit" variant="contained" color="primary" id="btn-search">
                <Search />
                </Button>
            </Grid>
            </Grid>
       
        </form>
        </div>
        <Outlet></Outlet>
      </>
        
  )
}

export default SearchBar
